	p = page.appendFloat('Valuea', label='Value A')
	p = page.appendFloat('Valueb', label='Value B')
	return

# called whenever custom pulse parameter is pushed
def onPulse(par):
	return

def cook(scriptOp):
	scriptOp.clear()
	scriptOp.appendRow(['path','parameter','value','enable'])

	inputDAT = scriptOp.inputs[0]
	camSchnappr = inputDAT[0,0]
	contentGeo = inputDAT[1,0]
	contentLight = inputDAT[2,0]
	targetSop = inputDAT[3,0]

	camSchnappr = set(camSchnappr.val.split(' '))
	cSFull = []
	for i in camSchnappr:
		if i.startswith('/'):
			cSFull += [x.path for x in ops(i) if x.type == 'cam']
		elif i.startswith('./'):
			cSFull += [x.path for x in parent().ops(i) if x.type == 'cam']
		elif i.startswith('../'):
			cSFull += [x.path for x in parent().ops(i) if x.type == 'cam']
		elif i != 'None':
			cSFull += [x.path for x in parent(2).ops(i) if x.type == 'cam']
	if len(cSFull):
		scriptOp.appendRow(['render1','camera','\''+cSFull[0]+'\'',1])
		renderTop = op(cSFull[0]).par.Rendertop.eval()
		geoSop = op(cSFull[0]).par.Geosop.eval()
		if renderTop and geoSop:
			scriptOp.appendRow(['render1','resolutionw',op(cSFull[0]).par.Rendertop.eval().par.resolutionw,1])
			scriptOp.appendRow(['render1','resolutionh',op(cSFull[0]).par.Rendertop.eval().par.resolutionh,1])
			scriptOp.appendRow(['selectScreen','sop','\''+op(cSFull[0]).par.Geosop.eval().path+'\'',1])
		else:
			debug('camSchnappr {0} has no Render and/or Sop specified.'.format(op(cSFull[0])))
	else:
		scriptOp.appendRow(['render1','camera','\'projectorCam\'',1])
		scriptOp.appendRow(['render1','resolutionw',parent().par.Resolutionw,1])
		scriptOp.appendRow(['render1','resolutionh',parent().par.Resolutionh,1])
		targetSop = set(targetSop.val.split(' '))
		tSFull = []
		for i in targetSop:
			if i.startswith('/'):
				tSFull += [x.path for x in ops(i) if x.family == 'SOP']
			elif i.startswith('./'):
				tSFull += [x.path for x in parent().ops(i) if x.family == 'SOP']
			elif i.startswith('../'):
				tSFull += [x.path for x in parent().ops(i) if x.family == 'SOP']
			elif i != 'None':
				tSFull += [x.path for x in parent(2).ops(i) if x.family == 'SOP']
		scriptOp.appendRow(['selectScreen','sop','\''+tSFull[0]+'\'',1])

	contentGeo = set(contentGeo.val.split(' '))
	cGFull = []
	for i in contentGeo:
		if i.startswith('/'):
			cGFull += [x.path for x in ops(i) if x.subType == 'object']
		elif i.startswith('./'):
			cGFull += [x.path for x in parent().ops(i) if x.subType == 'object']
		elif i.startswith('../'):
			cGFull += [x.path for x in parent().ops(i) if x.subType == 'object']
		elif i != 'None':
			cGFull += [x.path for x in parent(2).ops(i) if x.subType == 'object']
	if len(cGFull):
		scriptOp.appendRow(['sweetSpotRender','geometry','\''+' '.join(cGFull)+'\'',1])
	else:
		scriptOp.appendRow(['sweetSpotRender','geometry','\'contentGeo\'',1])

	contentLight = set(contentLight.val.split(' '))
	cLFull = []
	for i in contentLight:
		if i.startswith('/'):
			cLFull += [x.path for x in ops(i) if x.subType == 'object']
		elif i.startswith('./'):
			cLFull += [x.path for x in parent().ops(i) if x.subType == 'object']
		elif i.startswith('../'):
			cLFull += [x.path for x in parent().ops(i) if x.subType == 'object']
		elif i != 'None':
			cLFull += [x.path for x in parent(2).ops(i) if x.subType == 'object']
	if len(cLFull):
		scriptOp.appendRow(['sweetSpotRender','lights','\''+' '.join(cLFull)+'\'',1])
	else:
		scriptOp.appendRow(['sweetSpotRender','lights','\'contentLight\'',1])

	return
